mapper.update:
UPDATE posts
SET like_count = (
    SELECT COUNT(*)
    FROM post_likes pl
    WHERE pl.post_id = #{postId}
)
WHERE post_id = #{postId}
  AND deleted_at IS NULL

UPDATE comments
SET like_count = (
    SELECT COUNT(*)
    FROM comment_likes cl
    WHERE cl.comment_id = #{commentId}
)
WHERE comment_id = #{commentId}
  AND deleted_at IS NULL

UPDATE users
SET follower_count = (
    SELECT COUNT(*)
    FROM user_follow uf
    JOIN users follower ON follower.user_id = uf.follower
    WHERE uf.followee = #{userId}
      AND follower.deleted_at IS NULL
)
WHERE user_id = #{userId}
  AND deleted_at IS NULL

UPDATE users
SET followee_count = (
    SELECT COUNT(*)
    FROM user_follow uf
    JOIN users followee ON followee.user_id = uf.followee
    WHERE uf.follower = #{userId}
      AND followee.deleted_at IS NULL
)
WHERE user_id = #{userId}
  AND deleted_at IS NULL

UPDATE user_groups
SET member_count = (
    SELECT COUNT(*)
    FROM group_members gm
    JOIN users u ON u.user_id = gm.user_id
    WHERE gm.group_id = #{groupId}
      AND u.deleted_at IS NULL
)
WHERE group_id = #{groupId}
  AND deleted_at IS NULL
